... I missed that printifname is being referenced in ifclone.c as well, where the actual problem that the atexit() fixes is caused. So perhaps only printifname=1 in setifname is to be removed from setifname.

   --- a/sbin/ifconfig/ifconfig.c
   +++ b/sbin/ifconfig/ifconfig.c
   @@ -1307,7 +1307,6 @@ setifname(const char *val, int dummy __unused, int s,
                   free(newname);
                   err(1, "ioctl SIOCSIFNAME (set name)");
           }
   -       printifname = 1;
           strlcpy(name, newname, sizeof(name));
           free(newname);
    }

seems to do it.
